:root {
  --bg-card: #ffffff;
  --border-card: #e2e8f0;
  --color-primary: #0f766e;
  --color-primary-light: #ccfbf1;
  --color-accent: #f0fdf4;
  --color-tag-bg: #e0f2fe;
  --color-tag-text: #0369a1;
  --color-status-bg: #dcfce7;
  --color-status-text: #15803d;
  --color-heading: #0f172a;
  --color-label: #64748b;
  --color-value: #1e293b;
  --color-reading-bg: #f8fafc;
  --color-reading-border: #e2e8f0;
  --color-reading-value: #0f766e;
  --color-track: #e2e8f0;
  --color-fill: #0f766e;
  --color-phase-dot: #22c55e;
  --color-footer-text: #94a3b8;
}

.lab-card {
  background: var(--bg-card);
  border: 1.5px solid var(--border-card);
  border-radius: 14px;
  padding: 20px;
  max-width: 500px;
  display: flex;
  flex-direction: column;
  gap: 14px;
}

.lab-header {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 12px;
}

.lab-title-group {
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.lab-tag {
  font-size: 11px;
  font-weight: 700;
  letter-spacing: 0.06em;
  color: var(--color-tag-text);
  background: var(--color-tag-bg);
  padding: 2px 8px;
  border-radius: 4px;
  width: fit-content;
  text-transform: uppercase;
}

.lab-title {
  font-size: 17px;
  font-weight: 700;
  color: var(--color-heading);
  margin: 0;
  line-height: 1.3;
}

.status-badge {
  font-size: 12px;
  font-weight: 600;
  color: var(--color-status-text);
  background: var(--color-status-bg);
  padding: 4px 10px;
  border-radius: 20px;
  white-space: nowrap;
}

.lab-meta {
  display: flex;
  gap: 0;
  border: 1.5px solid var(--color-reading-border);
  border-radius: 10px;
  overflow: hidden;
}

.meta-item {
  flex: 1;
  display: flex;
  flex-direction: column;
  gap: 2px;
  padding: 10px 14px;
  border-right: 1.5px solid var(--color-reading-border);
}

.meta-item:last-child {
  border-right: none;
}

.meta-label {
  font-size: 11px;
  color: var(--color-label);
  font-weight: 500;
}

.meta-value {
  font-size: 13px;
  font-weight: 600;
  color: var(--color-value);
}

.readings-section {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.readings-title {
  font-size: 12px;
  font-weight: 600;
  color: var(--color-label);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  margin: 0;
}

.readings-grid {
  display: grid;
  grid-template-columns: repeat(4, 1fr);
  gap: 8px;
}

.reading-card {
  background: var(--color-reading-bg);
  border: 1.5px solid var(--color-reading-border);
  border-radius: 10px;
  padding: 10px 8px;
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
}

.reading-label {
  font-size: 10px;
  color: var(--color-label);
  font-weight: 500;
  text-align: center;
  line-height: 1.3;
}

.reading-value {
  font-size: 20px;
  font-weight: 700;
  color: var(--color-reading-value);
  line-height: 1;
}

.reading-unit {
  font-size: 10px;
  color: var(--color-label);
  font-weight: 400;
}

.progress-section {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.progress-header {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.progress-label {
  font-size: 12px;
  font-weight: 600;
  color: var(--color-label);
}

.progress-pct {
  font-size: 13px;
  font-weight: 700;
  color: var(--color-primary);
}

.progress-track {
  height: 8px;
  background: var(--color-track);
  border-radius: 99px;
  overflow: hidden;
}

.progress-fill {
  height: 100%;
  width: 73%;
  background: var(--color-fill);
  border-radius: 99px;
}

.lab-footer {
  display: flex;
  justify-content: space-between;
  align-items: center;
  padding-top: 6px;
  border-top: 1.5px solid var(--color-reading-border);
}

.phase-indicator {
  display: flex;
  align-items: center;
  gap: 7px;
}

.phase-dot {
  width: 8px;
  height: 8px;
  border-radius: 50%;
  background: var(--color-phase-dot);
}

.phase-text {
  font-size: 12px;
  font-weight: 600;
  color: var(--color-value);
}

.log-count {
  font-size: 12px;
  color: var(--color-footer-text);
  font-weight: 500;
}
